// 1. 📥 OBTENER DATOS DE FORMA SEGURA
// La respuesta de la IA viene del nodo actual
const aiNodeData = $input.first()?.json || {};
const respuestaIA = aiNodeData.output || aiNodeData.text || aiNodeData.response || "";

// Los datos originales los buscamos directo en la puerta de entrada (Webhook)
const webhookData = $('Webhook').first()?.json?.body || {};
const sessionId = webhookData.sessionId || webhookData.session_id || `session_${Date.now()}`;
const userId = webhookData.userId || webhookData.user_id || null;
const userMessage = webhookData.chatInput || webhookData.message || "";

// 2. 🧠 DETECCIÓN DE SECTOR Y CLIMA
const respuestaLower = respuestaIA.toLowerCase();

const sectoresPalabras = {
    'naval': ['naval', 'mar', 'puerto', 'navegación', 'barco', 'marítimo', 'olas', 'marea', 'nudos', 'douglas'],
    'agro': ['agrícola', 'cultivo', 'siembra', 'cosecha', 'campo', 'rural', 'agricultura', 'riego', 'suelo'],
    'aereo': ['aéreo', 'vuelo', 'aviación', 'aeropuerto', 'avión', 'cielo', 'metar', 'qnh'],
    'energia': ['energía', 'eléctrico', 'solar', 'eólico', 'renovable', 'panel', 'turbina', 'radiación']
};

let sectorDetectado = null;
for (const [sector, palabras] of Object.entries(sectoresPalabras)) {
    if (palabras.some(palabra => respuestaLower.includes(palabra))) {
        sectorDetectado = sector;
        break;
    }
}

const datosMeteorologicos = {
    temperatura: respuestaLower.includes('temperatura') || respuestaLower.includes('°c'),
    viento: respuestaLower.includes('viento') || respuestaLower.includes('km/h') || respuestaLower.includes('nudos') || respuestaLower.includes('kt'),
    humedad: respuestaLower.includes('humedad') || respuestaLower.includes('%'),
    precipitacion: respuestaLower.includes('lluvia') || respuestaLower.includes('precipitación') || respuestaLower.includes('mm')
};
const respuestaContieneClima = Object.values(datosMeteorologicos).some(Boolean);

// 3. 📊 EXTRACCIÓN DE POWER BI Y LIMPIEZA DE TEXTO (Regex Seguro)
// Buscamos la URL cruda
const urlRegex = /(https:\/\/app\.powerbi\.com[^\s\)]+)/;
const matchPowerBI = respuestaIA.match(urlRegex);
const powerbi_url = matchPowerBI ? matchPowerBI[0] : null;

// Limpiamos la respuesta para que el usuario no vea links feos, pero sin borrar texto útil
let texto_limpio = respuestaIA;
if (powerbi_url) {
    // Elimina el formato markdown [texto](url) si la IA lo usó
    texto_limpio = texto_limpio.replace(/\[.*?\]\(https:\/\/app\.powerbi\.com.*?\)/g, "");
    // Elimina la URL suelta por las dudas
    texto_limpio = texto_limpio.replace(powerbi_url, "");
}
texto_limpio = texto_limpio.trim();

// 4. 🏗️ CONSTRUIR OBJETOS NATIVOS PARA SUPABASE (Sin JSON.stringify)
const contextoPrevioObj = {
    sector_conversacion: sectorDetectado,
    contiene_datos_clima: respuestaContieneClima,
    timestamp_inicio: new Date().toISOString()
};

const metadatosObj = {
    user_agent: webhookData.headers?.['user-agent'] || null,
    ai_agent_used: true,
    datos_meteorologicos_detectados: datosMeteorologicos
};

// 5. 📤 ARMAR LA SALIDA FINAL PARA N8N
const outputCompleto = {
    // --- Datos para insertar en Supabase ---
    session_id: sessionId,
    user_id: userId,
    user_message: userMessage,
    ai_response: respuestaIA,
    sector: sectorDetectado,
    ubicacion: webhookData.ubicacion || null, // Objeto nativo
    contexto_previo: contextoPrevioObj,       // Objeto nativo
    metadatos: metadatosObj,                  // Objeto nativo

    // --- Datos para el Frontend (Respond to Webhook) ---
    output: respuestaIA,
    texto_limpio: texto_limpio,
    powerbi_url: powerbi_url,

    // --- Flags internos del workflow ---
    es_respuesta_climatica: respuestaContieneClima
};

return [{ json: outputCompleto }];

// 1. Obtenemos los datos del Webhook de forma segura (evita errores si el nodo cambia de nombre)
const webhookData = $('Webhook').first()?.json?.body || {};
const userMessage = webhookData.chatInput || webhookData.message || "";
const sessionId = webhookData.sessionId || webhookData.session_id || `session_${Date.now()}`;
const userId = webhookData.userId || webhookData.user_id || null;

// 🕐 2. CONFIGURACIÓN DE LÍMITES
const LIMITE_MENSAJES_MEMORIA = 10; // Cantidad máxima de intercambios
const LIMITE_CARACTERES_CONTEXTO = 4000; // Límite seguro para no saturar tokens de la IA

// 3. Obtener datos del nodo anterior (Supabase)
const inputItems = $input.all();
let datosMemoria = [];

if (inputItems && inputItems.length > 0) {
    // Filtramos para asegurarnos de que solo procesamos filas válidas de Supabase
    datosMemoria = inputItems
        .map(item => item.json)
        .filter(item => item && item.user_message && item.ai_response);
}

// Variables iniciales
let contextoTexto = "";
let esPrimeraInteraccion = true;
let intercambiosIncluidos = 0;

// 🧠 4. MOTOR DE MEMORIA (Lógica corregida)
if (datosMemoria.length > 0) {
    esPrimeraInteraccion = false;

    // PASO A: Ordenar de MÁS NUEVO a MÁS VIEJO
    // Usamos created_at o timestamp (lo que esté disponible en tu tabla)
    datosMemoria.sort((a, b) => new Date(b.created_at || b.timestamp) - new Date(a.created_at || a.timestamp));

    // PASO B: Tomar solo los últimos X mensajes
    const memoriaReciente = datosMemoria.slice(0, LIMITE_MENSAJES_MEMORIA);

    let bloquesValidos = [];
    let caracteresUsados = 0;

    // PASO C: Evaluar longitud (asegurando que siempre guardamos lo más reciente)
    for (const intercambio of memoriaReciente) {
        const bloque = `Usuario: ${intercambio.user_message}\nIA: ${intercambio.ai_response}\n\n`;

        if (caracteresUsados + bloque.length > LIMITE_CARACTERES_CONTEXTO) {
            break; // Si nos pasamos del límite, descartamos los mensajes más viejos
        }

        bloquesValidos.push(bloque);
        caracteresUsados += bloque.length;
        intercambiosIncluidos++;
    }

    // PASO D: Invertir el array para que la IA lo lea en orden cronológico natural (Viejo -> Nuevo)
    bloquesValidos.reverse();

    // PASO E: Armar el bloque de texto final
    if (bloquesValidos.length > 0) {
        contextoTexto = "### 📝 MEMORIA DE CONVERSACIÓN PREVIA ###\n";
        contextoTexto += bloquesValidos.join("");
        contextoTexto += "### FIN MEMORIA ###\n\n";
    }
}

// 📝 5. Instrucciones dinámicas para inyectar en el System Prompt
const instruccionesMemoria = esPrimeraInteraccion 
    ? "Esta es la primera interacción con este usuario en esta sesión. Responde a su solicitud directamente."
    : `Tienes contexto de los últimos ${intercambiosIncluidos} intercambios con el usuario. Úsalo para mantener la continuidad de la conversación.`;

// ️ 6. CONSTRUIR OUTPUT FINAL
const outputCompleto = {
    ...webhookData, // Pasamos de largo todo lo que venía del frontend
    session_id: sessionId,
    user_id: userId,
    mensaje_actual: userMessage,
    contexto_memoria: contextoTexto,
    es_primera_vez: esPrimeraInteraccion,
    numero_intercambios_previos: intercambiosIncluidos,
    instrucciones_memoria: instruccionesMemoria
};

// 📤 7. RETORNAR EN EL FORMATO NATIVO DE N8N
return [{ json: outputCompleto }];

// PREPARAR_VISION — Detecta imagenes y pre-analiza con Gemini Vision
const body = $input.first().json?.body ?? $input.first().json ?? {};
const imageUrl  = body?.imageUrl ?? body?.image_url ?? null;
const chatInput = body?.chatInput ?? body?.text ?? '';

if (!imageUrl) {
  return [{ json: $input.first().json }];
}

const apiKey = 'AIzaSyCp1N8gRFrr6_hMi_vlP-sRt63Q4hU52Ns';
let imageAnalysis = '';

try {
  const imgResp = await $http.request({
    method: 'GET',
    url: imageUrl,
    encoding: 'arraybuffer',
    returnFullResponse: true,
  });
  const base64Image = Buffer.from(imgResp.body).toString('base64');
  const mimeType = (imgResp.headers['content-type'] || 'image/jpeg').split(';')[0];

  const visionResp = await $http.request({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=' + apiKey,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      contents: [{ parts: [
        { text: 'Eres un experto tecnico en meteorologia, aviacion, navegacion maritima y agronomia. Analiza esta imagen con maximo detalle. Segun el tipo identifica: Radar/Mapa sinoptico: frentes, isobaras, zonas de conveccion, gradientes de presion. Carta de navegacion/aereo: SIGMET, turbulencia, icing, cizalladura. Foto cultivo/lote: estres hidrico, enfermedades, estado fenologico, danos. Foto energia: estado paneles/aerogeneradores. Contexto del usuario: ' + chatInput },
        { inlineData: { mimeType: mimeType, data: base64Image } }
      ]}],
      generationConfig: { temperature: 0.1, maxOutputTokens: 2000 }
    })
  });

  imageAnalysis = visionResp?.candidates?.[0]?.content?.parts?.[0]?.text ?? 'No se pudo extraer analisis.';
} catch (err) {
  imageAnalysis = 'Error al procesar imagen: ' + err.message;
}

return [{
  json: {
    body: {
      chatInput: '[ANALISIS VISUAL — VISION IA]\n' + imageAnalysis + '\n\n---\nConsulta del usuario: ' + chatInput + '\n\n[URL_IMAGEN]: ' + imageUrl,
      imageUrl: imageUrl,
      imageAnalysis: imageAnalysis,
      hasImage: true
    }
  }
}];
